import { Component } from '@angular/core';
import { NgForm } from '@angular/forms';
import { AuthService } from '../../../core/services/auth.service';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { Injectable } from '@angular/core';

@Injectable({
  providedIn: 'root'
})
export class DiseaseService {

  constructor(private http: HttpClient) { }

  searchDiseases(query: string): Observable<string[]> {
    return this.http.get<string[]>(`http://localhost:5000/diseases?search=${query}`);
  }
}

export class RegisterComponent {

  currentStep = 1;

  name = '';
  dob = '';
  mobile_no = '';
  gender = '';
  height: number | null = null;
  weight: number | null = null;
  bloodGroup = '';
  knownDiseases: string[] = [];
  diseaseInput: string = '';
  email = '';
  password = '';
  confirmPassword = '';
  allDiseases: string[] = [
    'Diabetes',
    'Hypertension',
    'Heart Disease',
    'Asthma',
    'Arthritis',
    'Thyroid',
    'Migraine',
    'PCOS',
    'Anemia',
    'Depression',
    'None'
  ];

  filteredDiseases: string[] = [];
  bloodGroups: string[] = [
    'A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'
  ];

  constructor(private authService: AuthService,
    private router: Router) { }

  nextStep() {
    this.currentStep = 2;
  }

  prevStep() {
    this.currentStep = 1;
  }

  handleSubmit(form: NgForm) {

    if (this.currentStep === 1) {

      if (!this.isStep1Valid()) {
        this.markTouched(form);
        return;
      }

      this.nextStep();
    }

    else {

      if (!this.isStep2Valid()) {
        this.markTouched(form);
        return;
      }

      this.register();
    }
  }

  isStep1Valid(): boolean {
    return (
      this.name?.length >= 3 &&
      !!this.dob &&
      /^[0-9]{10}$/.test(this.mobile_no) &&
      !!this.gender &&
      !!this.height && this.height >= 50 &&
      !!this.weight && this.weight >= 10 &&
      !!this.bloodGroup
    );
  }

  isStep2Valid(): boolean {
    return (
      /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(this.email) &&
      this.password?.length >= 6 &&
      this.confirmPassword === this.password
    );
  }

  markTouched(form: NgForm) {
    Object.values(form.controls).forEach(control => {
      control.markAsTouched();
    });
  }

  register() {

    const data = {
      name: this.name,
      dob: this.dob,
      mobile_no: this.mobile_no,
      gender: this.gender,
      height: this.height,
      weight: this.weight,
      bloodGroup: this.bloodGroup,
      email: this.email,
      password: this.password
    };

    this.authService.register(data).subscribe({
      next: () => {
        alert('Registration successful!');
        this.router.navigate(['/login']);
      },
      error: () => {
        alert('Registration failed.');
      }
    });
  }
  onDiseaseInput() {
    const value = this.diseaseInput.toLowerCase();

    if (!value) {
      this.filteredDiseases = [];
      return;
    }

    this.filteredDiseases = this.allDiseases.filter(d =>
      d.toLowerCase().includes(value) &&
      !this.knownDiseases.includes(d)
    );
  }

  selectDisease(disease: string) {
    if (!this.knownDiseases.includes(disease)) {
      this.knownDiseases.push(disease);
    }
    this.diseaseInput = '';
    this.filteredDiseases = [];
  }

  addDisease(event: KeyboardEvent) {
    event.preventDefault();
    const value = this.diseaseInput.trim();

    if (!value) return;

    if (!this.knownDiseases.includes(value)) {
      this.knownDiseases.push(value);
    }

    this.diseaseInput = '';
    this.filteredDiseases = [];
  }

  removeDisease(index: number) {
    this.knownDiseases.splice(index, 1);
  }
}
